CLASE CartaManager {  // AGGREGATE ROOT de /pizzepos/cartas/. TODO determinista (CRUD+versionado) -> candidato REFLEJO JS, no turno LLM.
  STORE_ACTUAL  = /pizzepos/cartas/<id>.json
  STORE_VERSION = /pizzepos/cartas/.versions/<id>/<ts>.json
  // ENTRADA event-driven:
  _on_carta_creada(evento) -> delega a save        // menu-generator publica carta.creada
  // LECTURA (no muta):
  get(carta_id) · list(filtros) · search(query,tipo) · stats() · versions(carta_id)
  // RAIZ (snapshot + version):
  save(carta)            -> si existe: snapshot+version++ ; persiste ; EMITE carta.actualizada ; auto-promo tarifas si config vacio
  restore(carta_id,ver)  -> snapshot actual -> restaura version -> version++ ; EMITE carta.actualizada
  clonar(base_id,nombre) -> copia INDEPENDIENTE id nuevo ; EMITE carta.actualizada
  delete(carta_id)       -> soft-delete (estado=archivada) + version++ ; EMITE carta.borrada
  // MUTACION ESTRUCTURADA (todas via el helper _mutar):
  add_product · remove_product · update_product · add_category · update_prices  -> EMITE carta.editada
  // HELPER comun (DRY del patron repetido en las 5 mutaciones):
  _mutar(carta_id, aplicar(carta)->patches) : read -> snapshot(.versions) -> aplicar -> fs.edit(patches) -> version++ + updated_at -> return carta
  INVARIANTES {
    cada mutacion: snapshot ANTES de sobrescribir (audit trail) + meta.version++ + evento canonico.
    otros carta-* LEEN via carta.<op>.request ; NUNCA escriben al store (carta-manager es el unico writer).
    write nuevo = fs.write atomico ; write sobre existente = fs.edit (RFC6902, sin componer el fichero entero).
  }
}
